import React, { useState, useEffect, useRef, useCallback } from "react";
import { useAuth } from "../context/AuthContext";
import MessageBubble from "../components/MessageBubble";

export default function Chat() {
  const { user, token, logout } = useAuth();
  const [sessions, setSessions] = useState([]);
  const [activeSessionId, setActiveSessionId] = useState(null);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [isStreaming, setIsStreaming] = useState(false);
  const [loadingSessions, setLoadingSessions] = useState(true);
  const [loadingMessages, setLoadingMessages] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [editingTitle, setEditingTitle] = useState("");
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const messagesEndRef = useRef(null);
  const textareaRef = useRef(null);

  const authHeaders = { Authorization: `Bearer ${token}` };

  useEffect(() => { fetchSessions(); }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = "auto";
      textareaRef.current.style.height = Math.min(textareaRef.current.scrollHeight, 160) + "px";
    }
  }, [input]);

  const fetchSessions = async () => {
    try {
      const res = await fetch("/api/chat/sessions", { headers: authHeaders });
      const data = await res.json();
      const list = data.sessions || [];
      setSessions(list);
      if (list.length > 0) loadSession(list[0].id);
    } catch (err) {
      console.error("fetchSessions error:", err);
    } finally {
      setLoadingSessions(false);
    }
  };

  const loadSession = async (sessionId) => {
    if (isStreaming) return;
    setActiveSessionId(sessionId);
    setLoadingMessages(true);
    setMessages([]);
    try {
      const res = await fetch(`/api/chat/sessions/${sessionId}`, { headers: authHeaders });
      if (!res.ok) throw new Error("Failed to load session");
      const data = await res.json();
      setMessages(data.session?.messages || []);
    } catch (err) {
      console.error("loadSession error:", err);
      setMessages([]);
    } finally {
      setLoadingMessages(false);
    }
  };

  const createNewSession = async () => {
    if (isStreaming) return;
    try {
      const res = await fetch("/api/chat/sessions", {
        method: "POST",
        headers: authHeaders,
      });
      const data = await res.json();
      const newSession = { ...data.session, messageCount: 0, preview: "Empty chat" };
      setSessions((prev) => [newSession, ...prev]);
      setActiveSessionId(data.session.id);
      setMessages([]);
    } catch (err) {
      console.error("createNewSession error:", err);
    }
  };

  const deleteSession = async (e, sessionId) => {
    e.stopPropagation();
    if (isStreaming && sessionId === activeSessionId) return;
    try {
      await fetch(`/api/chat/sessions/${sessionId}`, {
        method: "DELETE",
        headers: authHeaders,
      });
      const remaining = sessions.filter((s) => s.id !== sessionId);
      setSessions(remaining);
      if (activeSessionId === sessionId) {
        if (remaining.length > 0) loadSession(remaining[0].id);
        else { setActiveSessionId(null); setMessages([]); }
      }
    } catch (err) {
      console.error("deleteSession error:", err);
    }
  };

  const startRename = (e, session) => {
    e.stopPropagation();
    setEditingId(session.id);
    setEditingTitle(session.title);
  };

  const saveRename = async (sessionId) => {
    const title = editingTitle.trim();
    setEditingId(null);
    if (!title) return;
    try {
      await fetch(`/api/chat/sessions/${sessionId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json", ...authHeaders },
        body: JSON.stringify({ title }),
      });
      setSessions((prev) =>
        prev.map((s) => (s.id === sessionId ? { ...s, title } : s))
      );
    } catch (err) {
      console.error("saveRename error:", err);
    }
  };

  const sendMessage = async () => {
    const text = input.trim();
    if (!text || isStreaming) return;

    let sessionId = activeSessionId;

    // Auto-create a session if none is active
    if (!sessionId) {
      try {
        const res = await fetch("/api/chat/sessions", {
          method: "POST",
          headers: authHeaders,
        });
        const data = await res.json();
        sessionId = data.session.id;
        const newSession = { ...data.session, messageCount: 0, preview: "Empty chat" };
        setSessions((prev) => [newSession, ...prev]);
        setActiveSessionId(sessionId);
      } catch (err) {
        console.error("auto-create session error:", err);
        return;
      }
    }

    // Optimistically add user message to UI
    const userMsg = { role: "user", content: text, timestamp: new Date().toISOString() };
    const aiMsg = { role: "assistant", content: "", timestamp: new Date().toISOString() };
    setMessages((prev) => [...prev, userMsg, aiMsg]);
    setInput("");
    setIsStreaming(true);

    try {
      const res = await fetch(`/api/chat/sessions/${sessionId}/message`, {
        method: "POST",
        headers: { "Content-Type": "application/json", ...authHeaders },
        body: JSON.stringify({ message: text }),
      });

      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.error || "Request failed");
      }

      const reader = res.body.getReader();
      const decoder = new TextDecoder();

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        const lines = decoder.decode(value).split("\n");
        for (const line of lines) {
          if (!line.startsWith("data: ")) continue;
          try {
            const event = JSON.parse(line.slice(6));
            if (event.type === "text") {
              setMessages((prev) => {
                const updated = [...prev];
                updated[updated.length - 1] = {
                  ...updated[updated.length - 1],
                  content: updated[updated.length - 1].content + event.content,
                };
                return updated;
              });
            } else if (event.type === "title") {
              setSessions((prev) =>
                prev.map((s) => (s.id === sessionId ? { ...s, title: event.title } : s))
              );
            }
          } catch { /* skip malformed */ }
        }
      }

      // Update session preview in sidebar
      setSessions((prev) =>
        prev.map((s) =>
          s.id === sessionId
            ? { ...s, preview: text.slice(0, 60), messageCount: (s.messageCount || 0) + 2 }
            : s
        )
      );
    } catch (err) {
      setMessages((prev) => {
        const updated = [...prev];
        updated[updated.length - 1] = {
          ...updated[updated.length - 1],
          content: `⚠️ Error: ${err.message}. Please try again.`,
        };
        return updated;
      });
    } finally {
      setIsStreaming(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const formatDate = (ts) => {
    if (!ts) return "";
    const d = new Date(ts);
    const now = new Date();
    if (d.toDateString() === now.toDateString()) return "Today";
    const yesterday = new Date(now);
    yesterday.setDate(now.getDate() - 1);
    if (d.toDateString() === yesterday.toDateString()) return "Yesterday";
    return d.toLocaleDateString([], { month: "short", day: "numeric" });
  };

  return (
    <div className="chat-layout">
      {/* Sidebar */}
      <aside className={`sidebar ${sidebarOpen ? "open" : "closed"}`}>
        <div className="sidebar-header">
          <div className="brand">
            <svg width="28" height="28" viewBox="0 0 36 36" fill="none">
              <rect width="36" height="36" rx="10" fill="url(#sg)" />
              <path d="M10 18c0-4.4 3.6-8 8-8s8 3.6 8 8-3.6 8-8 8" stroke="white" strokeWidth="2.5" strokeLinecap="round" />
              <circle cx="18" cy="18" r="2.5" fill="white" />
              <defs>
                <linearGradient id="sg" x1="0" y1="0" x2="36" y2="36">
                  <stop offset="0%" stopColor="#6366f1" />
                  <stop offset="100%" stopColor="#8b5cf6" />
                </linearGradient>
              </defs>
            </svg>
            <span>NexusAI</span>
          </div>
          <button className="sidebar-toggle" onClick={() => setSidebarOpen(false)} title="Close sidebar">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <path d="M15 18l-6-6 6-6" />
            </svg>
          </button>
        </div>

        <div className="sidebar-new">
          <button className="new-chat-btn" onClick={createNewSession}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <path d="M12 5v14M5 12h14" />
            </svg>
            New Chat
          </button>
        </div>

        <div className="sessions-list">
          {loadingSessions ? (
            <div className="sessions-loading"><span className="spinner" /></div>
          ) : sessions.length === 0 ? (
            <div className="sessions-empty">No chats yet.<br />Click "New Chat" to start.</div>
          ) : (
            sessions.map((session) => (
              <div
                key={session.id}
                className={`session-item ${session.id === activeSessionId ? "active" : ""}`}
                onClick={() => loadSession(session.id)}
              >
                <div className="session-content">
                  {editingId === session.id ? (
                    <input
                      className="rename-input"
                      value={editingTitle}
                      autoFocus
                      onChange={(e) => setEditingTitle(e.target.value)}
                      onBlur={() => saveRename(session.id)}
                      onKeyDown={(e) => {
                        if (e.key === "Enter") saveRename(session.id);
                        if (e.key === "Escape") setEditingId(null);
                        e.stopPropagation();
                      }}
                      onClick={(e) => e.stopPropagation()}
                    />
                  ) : (
                    <>
                      <span className="session-title">{session.title}</span>
                      <span className="session-meta">
                        <span className="session-date">{formatDate(session.createdAt)}</span>
                        {session.messageCount > 0 && (
                          <span className="session-count">{session.messageCount} msgs</span>
                        )}
                      </span>
                    </>
                  )}
                </div>
                <div className="session-actions">
                  <button className="session-btn" onClick={(e) => startRename(e, session)} title="Rename">
                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                      <path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7M18.5 2.5a2.12 2.12 0 013 3L12 15l-4 1 1-4 9.5-9.5z" />
                    </svg>
                  </button>
                  <button className="session-btn delete" onClick={(e) => deleteSession(e, session.id)} title="Delete">
                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                      <path d="M3 6h18M8 6V4h8v2M19 6l-1 14H6L5 6" />
                    </svg>
                  </button>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="sidebar-footer">
          <div className="user-info">
            <div className="user-dot" />
            <span>{user}</span>
          </div>
          <button className="logout-btn" onClick={logout} title="Sign out">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <path d="M9 21H5a2 2 0 01-2-2V5a2 2 0 012-2h4M16 17l5-5-5-5M21 12H9" />
            </svg>
          </button>
        </div>
      </aside>

      {/* Main chat area */}
      <main className="chat-main">
        {/* Top bar when sidebar is closed */}
        {!sidebarOpen && (
          <div className="topbar">
            <button className="sidebar-toggle open" onClick={() => setSidebarOpen(true)} title="Open sidebar">
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M9 18l6-6-6-6" />
              </svg>
            </button>
            <span className="topbar-title">
              {sessions.find((s) => s.id === activeSessionId)?.title || "NexusAI"}
            </span>
            <button className="new-chat-icon" onClick={createNewSession} title="New chat">
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M12 5v14M5 12h14" />
              </svg>
            </button>
          </div>
        )}

        <div className="chat-messages">
          {loadingMessages ? (
            <div className="loading-state"><span className="spinner" /></div>
          ) : !activeSessionId || messages.length === 0 ? (
            <div className="empty-state">
              <div className="empty-icon">
                <svg width="52" height="52" viewBox="0 0 36 36" fill="none">
                  <rect width="36" height="36" rx="10" fill="url(#eg)" />
                  <path d="M10 18c0-4.4 3.6-8 8-8s8 3.6 8 8-3.6 8-8 8" stroke="white" strokeWidth="2.5" strokeLinecap="round" />
                  <circle cx="18" cy="18" r="2.5" fill="white" />
                  <defs>
                    <linearGradient id="eg" x1="0" y1="0" x2="36" y2="36">
                      <stop offset="0%" stopColor="#6366f1" />
                      <stop offset="100%" stopColor="#8b5cf6" />
                    </linearGradient>
                  </defs>
                </svg>
              </div>
              <h2>How can I help you today?</h2>
              <p>Type a message below to start the conversation.</p>
            </div>
          ) : (
            messages.map((msg, i) => (
              <MessageBubble
                key={i}
                message={msg}
                isStreaming={isStreaming && i === messages.length - 1 && msg.role === "assistant"}
              />
            ))
          )}
          <div ref={messagesEndRef} />
        </div>

        <div className="input-area">
          <div className="input-box">
            <textarea
              ref={textareaRef}
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Message NexusAI…"
              rows={1}
              disabled={isStreaming}
            />
            <button
              className={`send-btn ${isStreaming ? "streaming" : ""}`}
              onClick={sendMessage}
              disabled={!input.trim() || isStreaming}
            >
              {isStreaming ? (
                <span className="spinner white" />
              ) : (
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                  <path d="M22 2L11 13M22 2l-7 20-4-9-9-4 20-7z" />
                </svg>
              )}
            </button>
          </div>
          <p className="input-hint">Enter to send · Shift+Enter for new line</p>
        </div>
      </main>
    </div>
  );
}
